fn solve(n: i64) -> bool {
    let mut num = n;
    let mut sum = 0;
    let mut product = 1;

    while num > 0 {
        let digit = num % 10;
        sum += digit;
        product *= digit;
        num /= 10;
    }

    let total = sum + product;
    if total == 0 {
        false
    } else {
        n % total == 0
    }
}
